### 代码实现

```cpp
/* 代码头注释：消失的账单 - 数学推导法 */
// 核心技巧：通过方程求解，直接计算 A, B, C 的值，避免枚举。
#include <bits/stdc++.h>
using namespace std;
using ll = long long;
const int INF = 0x3f3f3f3f;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    ll n, m;
    cin >> n >> m;

    // 方程1：A + B + C = n
    // 方程2：1000B + 2500C = m
    // 通过方程2，可以解出 B = (m - 2500C) / 1000
    // 代入方程1，得到 A = n - B - C

    // 遍历 C 的可能值，计算 B 和 A
    // 由于 B 必须为非负整数，C 的最大值为 min(n, m / 2500)
    ll maxC = min(n, m / 2500);
    for (ll C = 0; C <= maxC; ++C) {
        ll remaining = m - 2500 * C;
        if (remaining < 0) continue; // 无解
        if (remaining % 1000 != 0) continue; // B 必须为整数
        ll B = remaining / 1000;
        ll A = n - B - C;
        if (A >= 0 && B >= 0) {
            cout << A << " " << B << " " << C << "\n";
            return 0;
        }
    }

    // 无解情况
    cout << "-1\n";
    return 0;
}
